20	// replayResp is the result of re-sending a request to upstream.
21	type replayResp struct {
22		Status         int                           `json:"status"`
23		DurationMS     int64                         `json:"duration_ms"`
24		Normalized     *normalize.NormalizedEnvelope `json:"normalized,omitempty"`
25		NormalizeError string                        `json:"normalize_error,omitempty"`
26		// ResponseBody is the raw upstream body (capped), so the UI can show what went
27		// wrong on a non-2xx — error JSON normalizes to empty final_text, which would
28		// otherwise render as a blank "—". Honest over polished; matches the raw-bytes
29		// ethos. Truncated marks that maxReplayBody clipped it.
30		ResponseBody string `json:"response_body,omitempty"`
31		Truncated    bool   `json:"truncated,omitempty"`
32	}
33	
34	// maxReplayBody caps the raw body returned inline so a huge (or streamed) response
35	// can't bloat the JSON. 64 KiB is plenty to read an error payload.
36	const maxReplayBody = 64 << 10
37	
38	var replayClient = &http.Client{Timeout: 10 * time.Minute}
39	
40	// capBody returns the body as a string, clipped to maxReplayBody, and whether it
41	// was clipped.
42	func capBody(b []byte) (string, bool) {
43		if len(b) > maxReplayBody {
44			return string(b[:maxReplayBody]), true
45		}
46		return string(b), false
47	}
48	
49	// handleReplay re-sends a captured completion to its upstream — optionally with a
50	// modified request body — and returns the freshly normalized result. Not
51	// persisted. Auth comes from the session's in-memory headers, so only sessions
52	// captured in THIS process can be replayed (credentials are never on disk).
53	func (s *Server) handleReplay(st *store.Store, w http.ResponseWriter, r *http.Request) {
54		id := r.PathValue("id")
55		detail, err := st.GetEvent(id)
56		if err == store.ErrNoRows {
57			http.Error(w, "event not found", http.StatusNotFound)
58			return
59		}
60		if err != nil {
61			httpError(w, err)
62			return
63		}
64		if !detail.IsCompletion {
65			http.Error(w, "only completion requests can be replayed", http.StatusBadRequest)
66			return
67		}
68		headers := s.Sessions.AuthFor(detail.SessionID)
69		if headers == nil {
70			http.Error(w, "no in-memory credentials for this session (captured before a restart or in another process); launch a new session to replay", http.StatusConflict)
71			return
72		}
73	
74		var in struct {
75			Body *string `json:"body"`
76		}
77		_ = json.NewDecoder(r.Body).Decode(&in)
78		var reqBody []byte
79		if in.Body != nil {
80			reqBody = []byte(*in.Body)
81		} else {
82			path, err := st.RawFilePath(id, "request_body")
83			if err != nil {
84				httpError(w, err)
85				return
86			}
87			if reqBody, err = os.ReadFile(path); err != nil {
88				httpError(w, err)
89				return
90			}
91		}
92	
93		out, err := s.executeReplay(r.Context(), detail.Method, detail.Target, reqBody, headers, detail.SessionID)
94		if err != nil {
95			http.Error(w, "replay failed: "+err.Error(), http.StatusBadGateway)
96			return
97		}
98		writeJSON(w, out)
99	}
