101	// executeReplay sends one request to upstream with the given auth headers and
102	// normalizes the response via the same registry capture uses. Shared by
103	// event-replay and replay-lib case runs.
104	func (s *Server) executeReplay(ctx context.Context, method, target string, body []byte, auth http.Header, sessionID string) (*replayResp, error) {
105		upReq, err := http.NewRequestWithContext(ctx, method, target, bytes.NewReader(body))
106		if err != nil {
107			return nil, err
108		}
109		applyReplayHeaders(upReq.Header, auth)
110		upReq.Header.Set("Accept-Encoding", "identity")
111	
112		started := time.Now().UTC()
113		resp, err := replayClient.Do(upReq)
114		if err != nil {
115			return nil, err
116		}
117		defer resp.Body.Close()
118		respBody, _ := io.ReadAll(resp.Body)
119		completed := time.Now().UTC()
120	
121		ev := buildReplayEvent(sessionID, target, method, auth.Get("Content-Type"), body, resp, respBody, started, completed)
122		out := &replayResp{Status: resp.StatusCode, DurationMS: completed.Sub(started).Milliseconds()}
123		out.ResponseBody, out.Truncated = capBody(respBody)
124		if env, err := s.reg.Normalize(ev); err != nil {
125			out.NormalizeError = err.Error()
126		} else {
127			out.Normalized = env
128		}
129		return out, nil
130	}
131	
132	// executeCaseThroughSession sends a replay-library case through the same launch
133	// session proxy path real clients use: /s/<token>/<endpoint>. The selected
134	// session supplies both upstream routing and credentials, while the case supplies
135	// only the request body plus session-relative endpoint.
136	func (s *Server) executeCaseThroughSession(ctx context.Context, proxyBase string, sess *httpcap.Session, method, endpoint string, body []byte, auth http.Header) (*replayResp, error) {
137		proxyTarget := strings.TrimRight(proxyBase, "/") + "/s/" + sess.Token + "/" + strings.TrimPrefix(endpoint, "/")
138		upstreamTarget := strings.TrimRight(sess.Upstream, "/") + "/" + strings.TrimPrefix(endpoint, "/")
139	
140		upReq, err := http.NewRequestWithContext(ctx, method, proxyTarget, bytes.NewReader(body))
141		if err != nil {
142			return nil, err
143		}
144		applyReplayHeaders(upReq.Header, auth)
145		upReq.Header.Set("Accept-Encoding", "identity")
146	
147		started := time.Now().UTC()
148		resp, err := replayClient.Do(upReq)
149		if err != nil {
150			return nil, err
151		}
152		defer resp.Body.Close()
153		respBody, _ := io.ReadAll(resp.Body)
154		completed := time.Now().UTC()
155	
156		ev := buildReplayEvent(sess.ID, upstreamTarget, method, auth.Get("Content-Type"), body, resp, respBody, started, completed)
157		out := &replayResp{Status: resp.StatusCode, DurationMS: completed.Sub(started).Milliseconds()}
158		out.ResponseBody, out.Truncated = capBody(respBody)
159		if env, err := s.reg.Normalize(ev); err != nil {
160			out.NormalizeError = err.Error()
161		} else {
162			out.Normalized = env
163		}
164		return out, nil
165	}
166	
167	// applyReplayHeaders copies auth/content headers onto the replay request, dropping
168	// ones the client must own per-send.
169	func applyReplayHeaders(dst, src http.Header) {
170		for k, vs := range src {
171			switch strings.ToLower(k) {
172			case "content-length", "host", "accept-encoding", "connection", "transfer-encoding":
173				continue
174			}
175			for _, v := range vs {
176				dst.Add(k, v)
177			}
178		}
179	}
180	
181	// buildReplayEvent shapes the upstream response into the same SourceEvent the
182	// capture proxy produces, so the normalize registry handles it unchanged.
183	func buildReplayEvent(sessionID, target, method, reqContentType string, reqBody []byte, resp *http.Response, respBody []byte, started, completed time.Time) *event.SourceEvent {
184		id := source.RandomID()
185		ev := event.New(id, event.KindHTTPExchange, event.SourceRef{
186			Kind:    event.SourceCapture,
187			Adapter: "replay",
188			Mode:    "replay",
189		})
190		ev.Correlation = event.Correlation{SessionID: sessionID}
191		ev.Timing = event.Timing{
192			StartedAt:   started.Format(time.RFC3339Nano),
193			CompletedAt: completed.Format(time.RFC3339Nano),
194			DurationMS:  completed.Sub(started).Milliseconds(),
195		}
196		reqArt := event.NewRawArtifact(id+":req", event.RoleRequestBody, reqBody)
197		reqArt.MediaType = reqContentType
198		respArt := event.NewRawArtifact(id+":resp", event.RoleResponseBody, respBody)
199		respArt.MediaType = resp.Header.Get("Content-Type")
200		ev.RawArtifacts = []event.RawArtifact{reqArt, respArt}
201		ev.Capture = &event.CaptureEvent{
202			Protocol: "http",
203			Method:   method,
204			URL:      target,
205			Target:   target,
206			Request: event.HTTPMessage{
207				ContentType:    reqContentType,
208				BodyArtifactID: reqArt.ID,
209				BodySizeBytes:  int64(len(reqBody)),
210			},
211			Response: event.HTTPMessage{
212				StatusCode:     resp.StatusCode,
213				ContentType:    resp.Header.Get("Content-Type"),
214				BodyArtifactID: respArt.ID,
215				BodySizeBytes:  int64(len(respBody)),
216			},
217		}
218		return &ev
219	}
