15	// handleListCases returns the replay library.
16	func (s *Server) handleListCases(st *store.Store, w http.ResponseWriter, _ *http.Request) {
17		cases, err := st.ListCases()
18		if err != nil {
19			httpError(w, err)
20			return
21		}
22		writeJSON(w, cases)
23	}
