25	// handleAddCase saves a captured event as a reusable case.
26	func (s *Server) handleAddCase(st *store.Store, w http.ResponseWriter, r *http.Request) {
27		payload, err := io.ReadAll(r.Body)
28		if err != nil {
29			http.Error(w, "invalid add-case request: "+err.Error(), http.StatusBadRequest)
30			return
31		}
32		var req struct {
33			EventID  string          `json:"event_id"`
34			Name     string          `json:"name"`
35			Tags     string          `json:"tags"`
36			Provider string          `json:"provider"`
37			Method   string          `json:"method"`
38			Target   string          `json:"target"`
39			Endpoint string          `json:"endpoint"`
40			Body     json.RawMessage `json:"body"`
41		}
42		if err := json.Unmarshal(payload, &req); err != nil {
43			http.Error(w, "invalid add-case request: "+err.Error(), http.StatusBadRequest)
44			return
45		}
46		if req.EventID == "" {
47			bodyRaw := req.Body
48			if len(bytes.TrimSpace(bodyRaw)) == 0 && isBareManualCasePayload(payload) {
49				bodyRaw = payload
50			}
51			body, err := manualCaseBody(bodyRaw)
52			if err != nil {
53				http.Error(w, "invalid manual case body: "+err.Error(), http.StatusBadRequest)
54				return
55			}
56			s.handleCreateManualCase(st, w, req.Name, req.Tags, req.Provider, req.Method, req.Target, req.Endpoint, body)
57			return
58		}
59		detail, err := st.GetEvent(req.EventID)
60		if err == store.ErrNoRows {
61			http.Error(w, "event not found", http.StatusNotFound)
62			return
63		}
64		if err != nil {
65			httpError(w, err)
66			return
67		}
68		path, err := st.RawFilePath(req.EventID, "request_body")
69		if err != nil {
70			httpError(w, err)
71			return
72		}
73		body, err := os.ReadFile(path)
74		if err != nil {
75			httpError(w, err)
76			return
77		}
78		name := req.Name
79		if name == "" {
80			name = detail.Model + " " + detail.Method
81		}
82		c := store.ReplayCase{
83			ID:       source.RandomID(),
84			Name:     name,
85			Tags:     req.Tags,
86			Provider: detail.Provider,
87			Method:   detail.Method,
88			Target:   detail.Target,
89			Endpoint: store.EndpointForTarget(detail.Provider, detail.Target, sourceUpstream(st, detail.SessionID)),
90			Body:     string(body),
91			Source:   "captured",
92		}
93		if err := st.AddCase(c); err != nil {
94			httpError(w, err)
95			return
96		}
97		writeJSON(w, c)
98	}
99	
100	func isBareManualCasePayload(payload []byte) bool {
101		var obj map[string]json.RawMessage
102		if err := json.Unmarshal(payload, &obj); err != nil {
103			return false
104		}
105		for _, key := range []string{"event_id", "name", "tags", "provider", "method", "target", "endpoint", "body"} {
106			if _, ok := obj[key]; ok {
107				return false
108			}
109		}
110		return len(obj) > 0
111	}
112	
113	func (s *Server) handleCreateManualCase(st *store.Store, w http.ResponseWriter, name, tags, provider, method, target, endpoint, body string) {
114		body = strings.TrimSpace(body)
115		if body == "" || !json.Valid([]byte(body)) {
116			http.Error(w, "invalid manual case request (valid JSON body required)", http.StatusBadRequest)
117			return
118		}
119		provider, endpoint = normalizeManualCaseRoute(provider, endpoint, body)
120		if method == "" {
121			method = "POST"
122		}
123		if name == "" {
124			name = defaultManualCaseName(body, method)
125		}
126		c := store.ReplayCase{
127			ID:       source.RandomID(),
128			Name:     name,
129			Tags:     tags,
130			Provider: provider,
131			Method:   method,
132			Target:   target,
133			Endpoint: endpoint,
134			Body:     body,
135			Source:   "manual",
136		}
137		if err := st.AddCase(c); err != nil {
138			httpError(w, err)
139			return
140		}
141		writeJSON(w, c)
142	}
143	
144	func manualCaseBody(raw json.RawMessage) (string, error) {
145		raw = bytes.TrimSpace(raw)
146		if len(raw) == 0 || bytes.Equal(raw, []byte("null")) {
147			return "", nil
148		}
149		var body string
150		if err := json.Unmarshal(raw, &body); err == nil {
151			return body, nil
152		}
153		return string(raw), nil
154	}
155	
156	func normalizeManualCaseRoute(provider, endpoint, body string) (string, string) {
157		if provider == "" {
158			provider = guessManualProvider(body)
159		}
160		if endpoint == "" {
161			if provider == "anthropic" {
162				endpoint = "/v1/messages"
163			} else {
164				endpoint = "/responses"
165			}
166		}
167		if !strings.HasPrefix(endpoint, "/") {
168			endpoint = "/" + endpoint
169		}
170		return provider, endpoint
171	}
172	
173	func guessManualProvider(body string) string {
174		var probe map[string]json.RawMessage
175		if json.Unmarshal([]byte(body), &probe) != nil {
176			return "openai-responses"
177		}
178		if _, ok := probe["messages"]; ok {
179			if _, hasMax := probe["max_tokens"]; hasMax {
180				return "anthropic"
181			}
182		}
183		return "openai-responses"
184	}
185	
186	func defaultManualCaseName(body, method string) string {
187		var probe struct {
188			Model string `json:"model"`
189		}
190		_ = json.Unmarshal([]byte(body), &probe)
191		if probe.Model != "" {
192			return probe.Model + " " + method
193		}
194		return "Manual " + method
195	}
