197	// handleSnapshotCase saves an edited body as a NEW case (a snapshot) derived from
198	// an existing one. The original is never mutated — captured/seed cases stay as the
199	// baseline while edits accumulate as separate, independently re-runnable snapshots.
200	func (s *Server) handleSnapshotCase(st *store.Store, w http.ResponseWriter, r *http.Request) {
201		base, err := st.GetCase(r.PathValue("id"))
202		if err == store.ErrNoRows {
203			http.Error(w, "case not found", http.StatusNotFound)
204			return
205		}
206		if err != nil {
207			httpError(w, err)
208			return
209		}
210		var req struct {
211			Name string `json:"name"`
212			Body string `json:"body"`
213		}
214		if err := json.NewDecoder(r.Body).Decode(&req); err != nil || req.Body == "" {
215			http.Error(w, "invalid snapshot request (body required)", http.StatusBadRequest)
216			return
217		}
218		name := req.Name
219		if name == "" {
220			name = base.Name + " (snapshot)"
221		}
222		c := store.ReplayCase{
223			ID:       source.RandomID(),
224			Name:     name,
225			Tags:     base.Tags,
226			Provider: base.Provider,
227			Method:   base.Method,
228			Target:   base.Target,
229			Endpoint: base.Endpoint,
230			Body:     req.Body,
231			Source:   "snapshot",
232		}
233		if err := st.AddCase(c); err != nil {
234			httpError(w, err)
235			return
236		}
237		writeJSON(w, c)
238	}
