240	// handleDeleteCase removes a case. Built-in seed cases are deletable too: the
241	// library is the user's to curate, and seeding is once-per-database (see
242	// store.seedCases), so a deleted built-in stays gone across restarts.
243	func (s *Server) handleDeleteCase(st *store.Store, w http.ResponseWriter, r *http.Request) {
244		c, err := st.GetCase(r.PathValue("id"))
245		if err == store.ErrNoRows {
246			http.Error(w, "case not found", http.StatusNotFound)
247			return
248		}
249		if err != nil {
250			httpError(w, err)
251			return
252		}
253		if err := st.DeleteCase(c.ID); err != nil {
254			httpError(w, err)
255			return
256		}
257		w.WriteHeader(http.StatusNoContent)
258	}
259	
260	// handleOverwriteCase saves an edited body back onto the SAME case (in-place),
261	// unlike snapshot which forks a new one. Irreversible — the original body is
262	// replaced — so the UI gates it behind a confirm. Works for any case, built-in
263	// included, now that the library is user-owned.
264	func (s *Server) handleOverwriteCase(st *store.Store, w http.ResponseWriter, r *http.Request) {
265		c, err := st.GetCase(r.PathValue("id"))
266		if err == store.ErrNoRows {
267			http.Error(w, "case not found", http.StatusNotFound)
268			return
269		}
270		if err != nil {
271			httpError(w, err)
272			return
273		}
274		var req struct {
275			Body string `json:"body"`
276		}
277		if err := json.NewDecoder(r.Body).Decode(&req); err != nil || req.Body == "" {
278			http.Error(w, "invalid overwrite request (body required)", http.StatusBadRequest)
279			return
280		}
281		c.Body = req.Body
282		if err := st.AddCase(*c); err != nil { // INSERT OR REPLACE on the same id
283			httpError(w, err)
284			return
285		}
286		writeJSON(w, c)
287	}
288	
289	// handleRunCase runs a case against a chosen session (which supplies credentials),
290	// optionally with an edited body. Real billed call; result is not persisted.
291	func (s *Server) handleRunCase(st *store.Store, w http.ResponseWriter, r *http.Request) {
292		id := r.PathValue("id")
293		c, err := st.GetCase(id)
294		if err == store.ErrNoRows {
295			http.Error(w, "case not found", http.StatusNotFound)
296			return
297		}
298		if err != nil {
299			httpError(w, err)
300			return
301		}
302		var req struct {
303			SessionID string  `json:"session_id"`
304			Body      *string `json:"body"`
305		}
306		_ = json.NewDecoder(r.Body).Decode(&req)
307		if req.SessionID == "" {
308			http.Error(w, "session_id required (it supplies the credentials)", http.StatusBadRequest)
309			return
310		}
311		sess := s.Sessions.Get(req.SessionID)
312		if sess == nil {
313			http.Error(w, "no live launch session for that id; launch a session first", http.StatusConflict)
314			return
315		}
316		auth := s.Sessions.AuthFor(req.SessionID)
317		if auth == nil {
318			http.Error(w, "no in-memory credentials for that session; launch a session first", http.StatusConflict)
319			return
320		}
321		body := c.Body
322		if req.Body != nil {
323			body = *req.Body
324		}
325		endpoint := c.Endpoint
326		if endpoint == "" {
327			endpoint = store.EndpointForTarget(c.Provider, c.Target, sess.Upstream)
328		}
329		out, err := s.executeCaseThroughSession(r.Context(), "http://"+r.Host, sess, c.Method, endpoint, []byte(body), auth)
330		if err != nil {
331			http.Error(w, "run failed: "+err.Error(), http.StatusBadGateway)
332			return
333		}
334		writeJSON(w, out)
335	}
336	
337	func sourceUpstream(st *store.Store, sessionID string) string {
338		ss, err := st.GetSession(sessionID)
339		if err != nil {
340			return ""
341		}
342		return ss.Upstream
343	}
